def get_odd_collatz(n: int) -> List[int]:
    collatz_sequence = []
    while n != 1:
        collatz_sequence.append(n)
        if n % 2 == 0:
            n = n // 2
        else:
            n = 3 * n + 1
    if n == 1:
        collatz_sequence.append(1)
    return sorted([num for num in collatz_sequence if num % 2 != 0])
